function LoginForm() {
  const searchParams = useSearchParams();
  const callbackUrl  = searchParams.get('callbackUrl') ?? '/';
  const error        = searchParams.get('error');

  return (
    <div style={{
      minHeight: '100vh',
      background: '#0c0c0c',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: "'InstrumentSans','Helvetica Neue',sans-serif",
    }}>
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        gap: 36,
        padding: '52px 44px',
        background: '#141412',
        border: '1px solid #232320',
        borderRadius: 10,
        width: '100%',
        maxWidth: 360,
      }}>

        <AntroLogo />

        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 13, fontWeight: 650, color: '#f2eee5', marginBottom: 6, letterSpacing: '-.01em' }}>
            Dashboard de Social Analytics
          </div>
          <div style={{ fontSize: 11, color: '#5c5a55', fontWeight: 450, lineHeight: 1.65 }}>
            Acesso restrito a membros<br />com email <span style={{ color: '#cdccca', fontWeight: 600 }}>@antro.ag</span>
          </div>
        </div>

        {error && (
          <div style={{
            width: '100%', padding: '10px 14px',
            background: 'rgba(239,68,68,.08)', border: '1px solid rgba(239,68,68,.2)',
            borderRadius: 6, fontSize: 11, color: '#ef4444', fontWeight: 450,
            textAlign: 'center',
          }}>
            {error === 'AccessDenied'
              ? 'Acesso negado — use seu email @antro.ag'
              : 'Erro ao autenticar. Tente novamente.'
            }
          </div>
        )}

        <button
          onClick={() => signIn('google', { callbackUrl })}
          style={{
            width: '100%',
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 12,
            padding: '12px 20px',
            background: '#f2eee5', color: '#0c0c0c',
            border: 'none', borderRadius: 6,
            fontFamily: "'InstrumentSans','Helvetica Neue',sans-serif",
            fontSize: 13, fontWeight: 600,
            cursor: 'pointer',
            transition: 'opacity .15s',
            letterSpacing: '-.01em',
          }}
          onMouseEnter={e => (e.currentTarget.style.opacity = '.88')}
          onMouseLeave={e => (e.currentTarget.style.opacity = '1')}
        >
          <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
            <path d="M17.64 9.2c0-.637-.057-1.251-.164-1.84H9v3.481h4.844c-.209 1.125-.843 2.078-1.796 2.717v2.258h2.908c1.702-1.567 2.684-3.875 2.684-6.615z" fill="#4285F4"/>
            <path d="M9 18c2.43 0 4.467-.806 5.956-2.18l-2.908-2.259c-.806.54-1.837.86-3.048.86-2.344 0-4.328-1.584-5.036-3.711H.957v2.332A8.997 8.997 0 0 0 9 18z" fill="#34A853"/>
            <path d="M3.964 10.71A5.41 5.41 0 0 1 3.682 9c0-.593.102-1.17.282-1.71V4.958H.957A8.996 8.996 0 0 0 0 9c0 1.452.348 2.827.957 4.042l3.007-2.332z" fill="#FBBC05"/>
            <path d="M9 3.58c1.321 0 2.508.454 3.44 1.345l2.582-2.58C13.463.891 11.426 0 9 0A8.997 8.997 0 0 0 .957 4.958L3.964 7.29C4.672 5.163 6.656 3.58 9 3.58z" fill="#EA4335"/>
          </svg>
          Entrar com Google
        </button>

        <div style={{ fontSize: 10, color: '#3a3935', fontWeight: 450, textAlign: 'center' }}>
          ANTRO · 2026
        </div>
      </div>
    </div>
  );
}

export default function LoginPage() {
  return (
    <Suspense>
      <LoginForm />
    </Suspense>
  );
}
